content.content:
   1→/* ==========================================================
   2→   ZodiacID — Production Stylesheet
   3→   Dark cosmic theme: navy #0f0e17, gold #d4a853
   4→   Fonts: Bebas Neue (display) + DM Sans (body)
   5→   ========================================================== */
   6→
   7→/* ========== CSS Custom Properties ========== */
   8→:root {
   9→  --bg-navy: #0f0e17;
  10→  --bg-card: #1a1929;
  11→  --bg-elevated: #232136;
  12→  --gold: #d4a853;
  13→  --gold-hover: #e0b96a;
  14→  --text: #e0dfe4;
  15→  --text-muted: #8b8a94;
  16→  --white: #ffffff;
  17→  --border: rgba(255, 255, 255, 0.08);
  18→  --accent-red: #c0392b;
  19→  --accent-purple: #7c3aed;
  20→  --accent-green: #27ae60;
  21→
  22→  --theme-red-primary: #c0392b;
  23→  --theme-red-bg: #2d1a1a;
  24→  --theme-parenting-primary: #7c3aed;
  25→  --theme-parenting-bg: #1e1a2d;
  26→
  27→  --font-display: 'Bebas Neue', sans-serif;
  28→  --font-body: 'DM Sans', sans-serif;
  29→
  30→  --container-max: 1120px;
  31→  --section-padding: 4rem 0;
  32→
  33→  --radius: 8px;
  34→  --radius-lg: 12px;
  35→  --radius-xl: 16px;
  36→}
  37→
  38→/* ========== Reset ========== */
  39→*, *::before, *::after {
  40→  box-sizing: border-box;
  41→  margin: 0;
  42→  padding: 0;
  43→}
  44→
  45→html {
  46→  scroll-behavior: smooth;
  47→  -webkit-text-size-adjust: 100%;
  48→}
  49→
  50→body {
  51→  font-family: var(--font-body);
  52→  background: var(--bg-navy);
  53→  color: var(--text);
  54→  font-size: 17px;
  55→  line-height: 1.75;
  56→  -webkit-font-smoothing: antialiased;
  57→  -moz-osx-font-smoothing: grayscale;
  58→}
  59→
  60→img {
  61→  max-width: 100%;
  62→  height: auto;
  63→  display: block;
  64→}
  65→
  66→a {
  67→  color: var(--gold);
  68→  text-decoration: none;
  69→  transition: color 0.2s;
  70→}
  71→
  72→a:hover {
  73→  color: var(--gold-hover);
  74→}
  75→
  76→ul, ol {
  77→  list-style: none;
  78→}
  79→
  80→/* ========== Skip Link (Accessibility) ========== */
  81→.skip-link {
  82→  position: absolute;
  83→  top: -100%;
  84→  left: 0;
  85→  background: var(--gold);
  86→  color: var(--bg-navy);
  87→  padding: 0.5rem 1rem;
  88→  z-index: 1000;
  89→  font-weight: 600;
  90→  border-radius: 0 0 var(--radius) 0;
  91→}
  92→
  93→.skip-link:focus {
  94→  top: 0;
  95→}
  96→
  97→/* ========== Layout ========== */
  98→.container {
  99→  max-width: var(--container-max);
 100→  margin: 0 auto;
 101→  padding: 0 1.5rem;
 102→}
 103→
 104→section {
 105→  padding: var(--section-padding);
 106→}
 107→
 108→/* ========== Typography ========== */
 109→h1, h2, h3, h4, h5, h6 {
 110→  font-family: var(--font-display);
 111→  color: var(--white);
 112→  line-height: 1.2;
 113→  letter-spacing: 0.02em;
 114→}
 115→
 116→h1 { font-size: 3rem; }
 117→h2 { font-size: 2rem; }
 118→h3 { font-size: 1.5rem; }
 119→h4 { font-size: 1.15rem; }
 120→
 121→p {
 122→  margin-bottom: 1rem;
 123→  line-height: 1.7;
 124→}
 125→
 126→.section-title {
 127→  font-family: var(--font-display);
 128→  font-size: 2rem;
 129→  color: var(--white);
 130→  margin-bottom: 1.5rem;
 131→  letter-spacing: 0.04em;
 132→  text-transform: uppercase;
 133→}
 134→
 135→.section-subtitle {
 136→  color: var(--text-muted);
 137→  font-size: 1.05rem;
 138→  margin-bottom: 2rem;
 139→  max-width: 640px;
 140→}
 141→
 142→/* ========== Buttons ========== */
 143→.btn {
 144→  display: inline-block;
 145→  padding: 0.7rem 1.5rem;
 146→  border-radius: var(--radius);
 147→  font-family: var(--font-body);
 148→  font-size: 0.95rem;
 149→  font-weight: 600;
 150→  cursor: pointer;
 151→  transition: all 0.2s;
 152→  border: none;
 153→  text-align: center;
 154→  text-decoration: none;
 155→}
 156→
 157→.btn-gold {
 158→  background: var(--gold);
 159→  color: var(--bg-navy);
 160→  font-weight: 700;
 161→}
 162→
 163→.btn-gold:hover {
 164→  background: var(--gold-hover);
 165→  color: var(--bg-navy);
 166→  transform: translateY(-1px);
 167→  box-shadow: 0 4px 15px rgba(212, 168, 83, 0.3);
 168→}
 169→
 170→.btn-gold:active {
 171→  transform: translateY(0);
 172→}
 173→
 174→.btn-gold:disabled {
 175→  opacity: 0.6;
 176→  cursor: not-allowed;
 177→  transform: none;
 178→  box-shadow: none;
 179→}
 180→
 181→.btn-outline {
 182→  background: transparent;
 183→  color: var(--gold);
 184→  border: 1px solid var(--gold);
 185→}
 186→
 187→.btn-outline:hover {
 188→  background: rgba(212, 168, 83, 0.1);
 189→  color: var(--gold-hover);
 190→}
 191→
 192→.btn-secondary {
 193→  background: var(--bg-elevated);
 194→  color: var(--text);
 195→  border: 1px solid var(--border);
 196→}
 197→
 198→.btn-secondary:hover {
 199→  background: var(--bg-card);
 200→  border-color: var(--gold);
 201→  color: var(--white);
 202→}
 203→
 204→.btn-lg {
 205→  padding: 1rem 2rem;
 206→  font-size: 1.1rem;
 207→}
 208→
 209→/* ========== Site Header ========== */
 210→.site-header {
 211→  position: sticky;
 212→  top: 0;
 213→  z-index: 200;
 214→  background: rgba(15, 14, 23, 0.95);
 215→  backdrop-filter: blur(10px);
 216→  border-bottom: 1px solid var(--border);
 217→  padding: 0.75rem 0;
 218→}
 219→
 220→.site-header .container {
 221→  display: flex;
 222→  align-items: center;
 223→  justify-content: space-between;
 224→}
 225→
 226→.site-logo {
 227→  font-family: var(--font-display);
 228→  font-size: 1.6rem;
 229→  color: var(--gold);
 230→  letter-spacing: 0.04em;
 231→  text-decoration: none;
 232→}
 233→
 234→.site-logo:hover {
 235→  color: var(--gold-hover);
 236→}
 237→
 238→.nav-links {
 239→  display: flex;
 240→  gap: 1.5rem;
 241→  align-items: center;
 242→}
 243→
 244→.nav-links a {
 245→  color: var(--text-muted);
 246→  font-size: 0.9rem;
 247→  font-weight: 500;
 248→  transition: color 0.2s;
 249→}
 250→
 251→.nav-links a:hover,
 252→.nav-links a.active {
 253→  color: var(--gold);
 254→}
 255→
 256→/* ========== Language Switcher ========== */
 257→.lang-switcher {
 258→  display: flex;
 259→  gap: 0.75rem;
 260→  align-items: center;
 261→  font-size: 0.8rem;
 262→  margin-left: 1rem;
 263→}
 264→
 265→.lang-switcher a {
 266→  color: var(--text-muted);
 267→  text-decoration: none;
 268→  transition: color 0.2s;
 269→}
 270→
 271→.lang-switcher a:hover {
 272→  color: var(--gold);
 273→}
 274→
 275→.lang-switcher .active {
 276→  color: var(--gold);
 277→  font-weight: 600;
 278→}
 279→
 280→.nav-toggle {
 281→  display: none;
 282→  background: none;
 283→  border: none;
 284→  color: var(--text);
 285→  font-size: 1.5rem;
 286→  cursor: pointer;
 287→  padding: 0.25rem;
 288→}
 289→
 290→/* ========== Hero ========== */
 291→.hero {
 292→  position: relative;
 293→  padding: 5rem 0 4rem;
 294→  overflow: hidden;
 295→  min-height: 520px;
 296→  display: flex;
 297→  align-items: center;
 298→}
 299→
 300→.hero .container {
 301→  position: relative;
 302→  z-index: 2;
 303→}
 304→
 305→.hero-title {
 306→  font-size: 3.5rem;
 307→  max-width: 640px;
 308→  line-height: 1.1;
 309→  margin-bottom: 1.25rem;
 310→}
 311→
 312→.hero-subline {
 313→  font-size: 1.15rem;
 314→  color: var(--text-muted);
 315→  max-width: 560px;
 316→  line-height: 1.7;
 317→  margin-bottom: 2rem;
 318→}
 319→
 320→.hero-actions {
 321→  display: flex;
 322→  gap: 1rem;
 323→  flex-wrap: wrap;
 324→}
 325→
 326→/* ========== Product Hero (interior pages) ========== */
 327→.product-hero {
 328→  padding: 3rem 0 2rem;
 329→  border-bottom: 1px solid var(--border);
 330→}
 331→
 332→.product-hero .hero-title {
 333→  font-size: 2.8rem;
 334→  margin-bottom: 0.5rem;
 335→}
 336→
 337→.product-hero .hero-subline {
 338→  margin-bottom: 0;
 339→}
 340→
 341→/* ========== Trust Strip ========== */
 342→.trust-strip {
 343→  text-align: center;
 344→  padding: 1.25rem 0;
 345→  color: var(--text-muted);
 346→  font-size: 0.85rem;
 347→  letter-spacing: 0.02em;
 348→  border-bottom: 1px solid var(--border);
 349→  background: var(--bg-card);
 350→}
 351→
 352→.trust-strip .separator {
 353→  margin: 0 0.75rem;
 354→  color: var(--gold);
 355→  opacity: 0.6;
 356→}
 357→
 358→/* ========== Card Grid ========== */
 359→.card-grid {
 360→  display: grid;
 361→  grid-template-columns: repeat(auto-fit, minmax(260px, 1fr));
 362→  gap: 1.25rem;
 363→}
 364→
 365→.card {
 366→  background: var(--bg-card);
 367→  border: 1px solid var(--border);
 368→  border-radius: var(--radius-lg);
 369→  padding: 1.75rem;
 370→  display: flex;
 371→  flex-direction: column;
 372→  transition: border-color 0.2s, transform 0.2s;
 373→}
 374→
 375→.card:hover {
 376→  border-color: rgba(212, 168, 83, 0.2);
 377→  transform: translateY(-2px);
 378→}
 379→
 380→.card h3 {
 381→  font-size: 1.3rem;
 382→  margin-bottom: 0.5rem;
 383→}
 384→
 385→.card .price {
 386→  color: var(--gold);
 387→  font-size: 1.5rem;
 388→  font-weight: 700;
 389→  margin-bottom: 0.75rem;
 390→}
 391→
 392→.card p {
 393→  color: var(--text-muted);
 394→  font-size: 1rem;
 395→  line-height: 1.7;
 396→}
 397→
 398→.card-actions {
 399→  display: flex;
 400→  gap: 0.75rem;
 401→  margin-top: auto;
 402→  padding-top: 1.25rem;
 403→  flex-wrap: wrap;
 404→}
 405→
 406→.card .badge {
 407→  display: inline-block;
 408→  background: rgba(212, 168, 83, 0.15);
 409→  color: var(--gold);
 410→  padding: 0.2rem 0.6rem;
 411→  border-radius: 3px;
 412→  font-size: 0.7rem;
 413→  font-weight: 700;
 414→  text-transform: uppercase;
 415→  letter-spacing: 0.06em;
 416→  margin-bottom: 0.75rem;
 417→}
 418→
 419→/* ========== Theme Variants ========== */
 420→.theme-red .card {
 421→  border-color: rgba(192, 57, 43, 0.2);
 422→}
 423→.theme-red .card:hover {
 424→  border-color: rgba(192, 57, 43, 0.4);
 425→}
 426→.theme-red .section-title,
 427→.theme-red .card h3 {
 428→  color: var(--theme-red-primary);
 429→}
 430→
 431→.theme-parenting .card {
 432→  border-color: rgba(124, 58, 237, 0.2);
 433→}
 434→.theme-parenting .card:hover {
 435→  border-color: rgba(124, 58, 237, 0.4);
 436→}
 437→.theme-parenting .section-title,
 438→.theme-parenting .card h3 {
 439→  color: var(--theme-parenting-primary);
 440→}
 441→
 442→/* ========== Steps (How It Works) ========== */
 443→.steps {
 444→  counter-reset: steps;
 445→  display: grid;
 446→  grid-template-columns: repeat(auto-fit, minmax(220px, 1fr));
 447→  gap: 1.5rem;
 448→}
 449→
 450→.steps li {
 451→  counter-increment: steps;
 452→  background: var(--bg-card);
 453→  border: 1px solid var(--border);
 454→  border-radius: var(--radius);
 455→  padding: 1.5rem;
 456→  position: relative;
 457→}
 458→
 459→.steps li::before {
 460→  content: counter(steps);
 461→  display: block;
 462→  font-family: var(--font-display);
 463→  font-size: 2rem;
 464→  color: var(--gold);
 465→  margin-bottom: 0.5rem;
 466→  line-height: 1;
 467→}
 468→
 469→.steps li h4 {
 470→  margin-bottom: 0.5rem;
 471→}
 472→
 473→.steps li p {
 474→  color: var(--text-muted);
 475→  font-size: 0.9rem;
 476→}
 477→
 478→/* ========== Testimonials ========== */
 479→.testimonials {
 480→  display: grid;
 481→  grid-template-columns: repeat(auto-fit, minmax(280px, 1fr));
 482→  gap: 1.25rem;
 483→}
 484→
 485→.testimonial {
 486→  background: var(--bg-card);
 487→  border: 1px solid var(--border);
 488→  border-radius: var(--radius);
 489→  padding: 1.5rem;
 490→}
 491→
 492→.testimonial p {
 493→  font-style: italic;
 494→  color: var(--text);
 495→  line-height: 1.7;
 496→  margin-bottom: 0.75rem;
 497→}
 498→
 499→.testimonial cite {
 500→  display: block;
 501→  font-style: normal;
 502→  font-size: 0.85rem;
 503→  color: var(--gold);
 504→}
 505→
 506→
 507→/* ========== Sticky CTA Bar ========== */
 508→.sticky-cta {
 509→  position: sticky;
 510→  bottom: 0;
 511→  background: var(--bg-card);
 512→  border-top: 1px solid var(--border);
 513→  padding: 1rem 2rem;
 514→  display: flex;
 515→  align-items: center;
 516→  justify-content: center;
 517→  gap: 1.5rem;
 518→  z-index: 100;
 519→  box-shadow: 0 -4px 20px rgba(0, 0, 0, 0.3);
 520→}
 521→
 522→.sticky-cta .cta-text {
 523→  color: var(--text);
 524→  font-size: 1rem;
 525→}
 526→
 527→.sticky-cta .btn-gold {
 528→  white-space: nowrap;
 529→}
 530→
 531→/* ========== Full Report Layout ========== */
 532→.report-full {
 533→  max-width: 720px;
 534→  margin: 0 auto;
 535→  padding: 2rem 1rem;
 536→}
 537→
 538→.report-full h2 {
 539→  color: var(--gold);
 540→  font-family: var(--font-display);
 541→  font-size: 1.6rem;
 542→  margin-top: 3rem;
 543→  margin-bottom: 1rem;
 544→  letter-spacing: 0.02em;
 545→}
 546→
 547→.report-full h3 {
 548→  color: var(--white);
 549→  font-size: 1.2rem;
 550→  margin-top: 2rem;
 551→  margin-bottom: 0.75rem;
 552→}
 553→
 554→.report-full p {
 555→  line-height: 1.85;
 556→  margin-bottom: 1rem;
 557→  color: var(--text);
 558→  font-size: 0.95rem;
 559→}
 560→
 561→.report-full ul,
 562→.report-full ol {
 563→  margin-bottom: 1rem;
 564→  padding-left: 1.5rem;
 565→}
 566→
 567→.report-full li {
 568→  list-style: disc;
 569→  margin-bottom: 0.4rem;
 570→  color: var(--text);
 571→  font-size: 0.95rem;
 572→  line-height: 1.7;
 573→}
 574→
 575→.report-full ol li {
 576→  list-style: decimal;
 577→}
 578→
 579→/* ========== Trust Strip ========== */
 580→.trust-bar {
 581→  background: var(--bg-card);
 582→  border: 1px solid var(--border);
 583→  border-radius: var(--radius-lg);
 584→  padding: 1.25rem 1.5rem;
 585→  text-align: center;
 586→  color: var(--text-muted);
 587→  font-size: 0.9rem;
 588→}
 589→
 590→/* ========== Report Excerpt ========== */
 591→.report-excerpt {
 592→  background: var(--bg-card);
 593→  border-left: 3px solid var(--gold);
 594→  padding: 1.5rem 1.5rem 1.5rem 2rem;
 595→  border-radius: 0 var(--radius) var(--radius) 0;
 596→  margin: 1.5rem 0;
 597→  color: var(--text);
 598→  line-height: 1.85;
 599→  font-size: 0.95rem;
 600→}
 601→
 602→.report-excerpt cite {
 603→  display: block;
 604→  margin-top: 1rem;
 605→  font-style: normal;
 606→  font-size: 0.9rem;
 607→  color: var(--gold);
 608→}
 609→
 610→/* ========== Natal Wheel Image ========== */
 611→.wheel-image {
 612→  width: 100%;
 613→  max-width: 420px;
 614→  border-radius: var(--radius-lg);
 615→  border: 1px solid var(--border);
 616→  box-shadow: 0 0 40px rgba(212, 168, 83, 0.08);
 617→}
 618→
 619→.wheel-image-hero {
 620→  position: absolute;
 621→  right: -5%;
 622→  top: 50%;
 623→  transform: translateY(-50%);
 624→  opacity: 0.12;
 625→  max-width: 500px;
 626→  pointer-events: none;
 627→}
 628→
 629→.wheel-glow {
 630→  filter: drop-shadow(0 0 20px rgba(212, 168, 83, 0.15));
 631→}
 632→
 633→/* ========== Feature Grid ========== */
 634→.feature-grid {
 635→  display: grid;
 636→  grid-template-columns: repeat(3, 1fr);
 637→  gap: 1.25rem;
 638→}
 639→
 640→.feature-item {
 641→  background: var(--bg-card);
 642→  border: 1px solid var(--border);
 643→  border-radius: var(--radius);
 644→  padding: 1.25rem;
 645→}
 646→
 647→.feature-item h4 {
 648→  color: var(--gold);
 649→  font-size: 1rem;
 650→  margin-bottom: 0.5rem;
 651→}
 652→
 653→.feature-item p {
 654→  color: var(--text-muted);
 655→  font-size: 0.9rem;
 656→  line-height: 1.6;
 657→}
 658→
 659→/* ========== Comparison Table ========== */
 660→.compare-table {
 661→  width: 100%;
 662→  border-collapse: collapse;
 663→  margin: 1.5rem 0;
 664→}
 665→
 666→.compare-table th,
 667→.compare-table td {
 668→  padding: 0.75rem 1rem;
 669→  text-align: left;
 670→  border-bottom: 1px solid var(--border);
 671→  font-size: 0.95rem;
 672→}
 673→
 674→.compare-table th {
 675→  color: var(--text-muted);
 676→  font-weight: 600;
 677→  font-size: 0.85rem;
 678→  text-transform: uppercase;
 679→  letter-spacing: 0.04em;
 680→}
 681→
 682→.compare-table td:first-child { color: var(--text); }
 683→.compare-table .us { color: var(--gold); font-weight: 600; }
 684→.compare-table .them { color: var(--text-muted); }
 685→
 686→/* ========== Chart Badges ========== */
 687→.chart-badges {
 688→  display: flex;
 689→  flex-wrap: wrap;
 690→  gap: 0.75rem;
 691→  margin: 1rem 0;
 692→}
 693→
 694→.chart-badge {
 695→  background: var(--bg-elevated);
 696→  border: 1px solid var(--border);
 697→  border-radius: var(--radius);
 698→  padding: 0.4rem 0.85rem;
 699→  font-size: 0.85rem;
 700→}
 701→
 702→.chart-badge strong {
 703→  color: var(--gold);
 704→  margin-right: 0.35rem;
 705→}
 706→
 707→/* ========== Order Form ========== */
 708→.order-form {
 709→  background: var(--bg-card);
 710→  border: 1px solid var(--border);
 711→  border-radius: var(--radius-lg);
 712→  padding: 2rem;
 713→  max-width: 560px;
 714→  margin: 2rem auto;
 715→}
 716→
 717→.order-form h3 {
 718→  text-align: center;
 719→  margin-bottom: 0.5rem;
 720→}
 721→
 722→.order-form .form-price {
 723→  text-align: center;
 724→  font-size: 1.5rem;
 725→  color: var(--gold);
 726→  font-weight: 700;
 727→  margin-bottom: 1.5rem;
 728→}
 729→
 730→.order-form .form-divider {
 731→  border: none;
 732→  border-top: 1px solid var(--border);
 733→  margin: 1.5rem 0;
 734→}
 735→
 736→.order-form .form-section-label {
 737→  color: var(--gold);
 738→  font-weight: 600;
 739→  font-size: 0.9rem;
 740→  text-transform: uppercase;
 741→  letter-spacing: 0.04em;
 742→  margin-bottom: 1rem;
 743→}
 744→
 745→.form-group {
 746→  margin-bottom: 1rem;
 747→}
 748→
 749→.form-group label {
 750→  display: block;
 751→  font-size: 0.85rem;
 752→  color: var(--text-muted);
 753→  margin-bottom: 0.35rem;
 754→  font-weight: 500;
 755→}
 756→
 757→.form-group input,
 758→.form-group select,
 759→.form-group textarea {
 760→  width: 100%;
 761→  padding: 0.65rem 0.85rem;
 762→  background: var(--bg-elevated);
