  1→/* ==========================================================
  2→   ZodiacID — Main JavaScript
  3→   Cookie consent, GA4, form handling, smooth scroll, mobile nav
  4→   ========================================================== */
  5→
  6→(function () {
  7→  'use strict';
  8→
  9→  // ========== Cookie Consent ==========
 10→  const CONSENT_KEY = 'cookie_consent';
 11→  const GA4_ID = 'G-XXXXXXXXXX'; // Replace with actual GA4 ID
 12→
 13→  function initCookieConsent() {
 14→    const consent = localStorage.getItem(CONSENT_KEY);
 15→
 16→    if (consent === 'accepted') {
 17→      loadGA4();
 18→      return;
 19→    }
 20→
 21→    if (consent === 'declined') {
 22→      return;
 23→    }
 24→
 25→    // Show banner
 26→    const banner = document.getElementById('cookie-banner');
 27→    if (banner) {
 28→      banner.classList.remove('hidden');
 29→
 30→      banner.querySelector('.btn-accept')?.addEventListener('click', function () {
 31→        localStorage.setItem(CONSENT_KEY, 'accepted');
 32→        banner.classList.add('hidden');
 33→        loadGA4();
 34→      });
 35→
 36→      banner.querySelector('.btn-decline')?.addEventListener('click', function () {
 37→        localStorage.setItem(CONSENT_KEY, 'declined');
 38→        banner.classList.add('hidden');
 39→      });
 40→    }
 41→  }
 42→
 43→  function loadGA4() {
 44→    if (document.querySelector('script[src*="googletagmanager"]')) return;
 45→
 46→    var script = document.createElement('script');
 47→    script.async = true;
 48→    script.src = 'https://www.googletagmanager.com/gtag/js?id=' + GA4_ID;
 49→    document.head.appendChild(script);
 50→
 51→    window.dataLayer = window.dataLayer || [];
 52→    function gtag() { window.dataLayer.push(arguments); }
 53→    window.gtag = gtag;
 54→    gtag('js', new Date());
 55→    gtag('config', GA4_ID);
 56→
 57→    initScrollTracking();
 58→    initCTATracking();
 59→  }
 60→
 61→  // ========== GA4 Event Tracking ==========
 62→  function trackEvent(name, params) {
 63→    if (typeof window.gtag === 'function') {
 64→      window.gtag('event', name, params);
 65→    }
 66→  }
 67→
 68→  function initCTATracking() {
 69→    document.querySelectorAll('.btn-gold, .btn-outline').forEach(function (btn) {
 70→      btn.addEventListener('click', function () {
 71→        trackEvent('cta_click', {
 72→          product: btn.dataset.product || 'unknown',
 73→          location: btn.dataset.location || 'unknown',
 74→          text: btn.textContent.trim().substring(0, 50)
 75→        });
 76→      });
 77→    });
 78→  }
 79→
 80→  function initScrollTracking() {
 81→    var thresholds = [25, 50, 75, 100];
 82→    var fired = {};
 83→
 84→    window.addEventListener('scroll', function () {
 85→      var scrollTop = window.pageYOffset || document.documentElement.scrollTop;
 86→      var docHeight = document.documentElement.scrollHeight - window.innerHeight;
 87→      if (docHeight <= 0) return;
 88→      var percent = Math.round((scrollTop / docHeight) * 100);
 89→
 90→      thresholds.forEach(function (t) {
 91→        if (percent >= t && !fired[t]) {
 92→          fired[t] = true;
 93→          trackEvent('scroll_depth', { percent: t });
 94→        }
 95→      });
 96→    }, { passive: true });
 97→  }
 98→
 99→  // ========== Form Handling ==========
100→  function initForms() {
101→    document.querySelectorAll('.order-form form, .contact-form form').forEach(function (form) {
102→      form.addEventListener('submit', function (e) {
103→        e.preventDefault();
104→
105→        // Validate required fields
106→        var valid = true;
107→        form.querySelectorAll('[required]').forEach(function (field) {
108→          var group = field.closest('.form-group') || field.closest('.form-checkbox');
109→          if (!group) return;
110→
111→          if (field.type === 'checkbox') {
112→            if (!field.checked) {
113→              valid = false;
114→              group.classList.add('has-error');
115→              var err = group.querySelector('.field-error');
116→              if (err) err.style.display = 'block';
117→            } else {
118→              group.classList.remove('has-error');
119→              var err = group.querySelector('.field-error');
120→              if (err) err.style.display = 'none';
121→            }
122→          } else {
123→            if (!field.value.trim()) {
124→              valid = false;
125→              group.classList.add('has-error');
126→              var err = group.querySelector('.field-error');
127→              if (err) err.style.display = 'block';
128→            } else {
129→              group.classList.remove('has-error');
130→              var err = group.querySelector('.field-error');
131→              if (err) err.style.display = 'none';
132→            }
133→          }
134→        });
135→
136→        if (!valid) return;
137→
138→        // Disable submit button
139→        var submitBtn = form.querySelector('button[type="submit"]');
140→        if (submitBtn) {
141→          submitBtn.disabled = true;
142→          submitBtn.textContent = 'Submitting...';
143→        }
144→
145→        // Submit via fetch (Web3Forms)
146→        var formData = new FormData(form);
147→
148→        fetch(form.action, {
149→          method: 'POST',
150→          body: formData
151→        })
152→          .then(function (res) { return res.json(); })
153→          .then(function (data) {
154→            if (data.success) {
155→              // Show success message
156→              var formEl = form.closest('.order-form') || form.closest('.contact-form');
157→              if (formEl) {
158→                form.style.display = 'none';
159→                var success = formEl.querySelector('.form-success');
160→                if (success) success.style.display = 'block';
161→              }
162→
163→              trackEvent('form_submit', {
164→                product: formData.get('product') || 'contact',
165→                price: formData.get('price') || '0'
166→              });
167→            } else {
168→              if (submitBtn) {
169→                submitBtn.disabled = false;
170→                submitBtn.textContent = submitBtn.dataset.originalText || 'Submit';
171→              }
172→              alert('Something went wrong. Please try again or email us at contact@zodiacid.com');
173→            }
174→          })
175→          .catch(function () {
176→            if (submitBtn) {
177→              submitBtn.disabled = false;
178→              submitBtn.textContent = submitBtn.dataset.originalText || 'Submit';
179→            }
180→            alert('Connection error. Please try again or email us at contact@zodiacid.com');
181→          });
182→      });
183→
184→      // Clear error on input
185→      form.querySelectorAll('input, select, textarea').forEach(function (field) {
186→        field.addEventListener('input', function () {
187→          var group = field.closest('.form-group');
188→          if (group) {
189→            group.classList.remove('has-error');
190→            var err = group.querySelector('.field-error');
191→            if (err) err.style.display = 'none';
192→          }
193→        });
194→      });
195→
196→      // Store original button text
197→      var submitBtn = form.querySelector('button[type="submit"]');
198→      if (submitBtn) {
199→        submitBtn.dataset.originalText = submitBtn.textContent;
200→      }
201→    });
202→  }
203→
204→  // ========== Smooth Scroll ==========
205→  function initSmoothScroll() {
206→    document.querySelectorAll('a[href^="#"]').forEach(function (link) {
207→      link.addEventListener('click', function (e) {
208→        var targetId = this.getAttribute('href');
209→        if (targetId === '#') return;
210→
211→        var target = document.querySelector(targetId);
212→        if (target) {
213→          e.preventDefault();
214→          target.scrollIntoView({ behavior: 'smooth', block: 'start' });
215→        }
216→      });
217→    });
218→  }
219→
220→  // ========== Mobile Navigation ==========
221→  function initMobileNav() {
222→    var toggle = document.querySelector('.nav-toggle');
223→    var nav = document.querySelector('.nav-links');
224→
225→    if (toggle && nav) {
226→      toggle.addEventListener('click', function () {
227→        nav.classList.toggle('open');
228→        var isOpen = nav.classList.contains('open');
229→        toggle.setAttribute('aria-expanded', isOpen);
230→        toggle.innerHTML = isOpen ? '&#x2715;' : '&#9776;';
231→      });
232→
233→      // Close on link click
234→      nav.querySelectorAll('a').forEach(function (link) {
235→        link.addEventListener('click', function () {
236→          nav.classList.remove('open');
237→          toggle.setAttribute('aria-expanded', 'false');
238→          toggle.innerHTML = '&#9776;';
239→        });
240→      });
241→    }
242→  }
243→
244→  // ========== Sample Page Tabs ==========
245→  function initTabs() {
246→    document.querySelectorAll('.tabs').forEach(function (tabContainer) {
247→      var buttons = tabContainer.querySelectorAll('.tab-btn');
248→      var panels = Array.from(tabContainer.parentElement.children).filter(function (el) {
249→        return el.classList.contains('tab-panel');
250→      });
251→
252→      buttons.forEach(function (btn) {
253→        btn.addEventListener('click', function () {
254→          var target = btn.dataset.tab;
255→
256→          buttons.forEach(function (b) {
257→            b.classList.remove('active');
258→            b.setAttribute('aria-selected', 'false');
259→          });
260→          panels.forEach(function (p) { p.classList.remove('active'); });
261→
262→          btn.classList.add('active');
263→          btn.setAttribute('aria-selected', 'true');
264→          var panel = document.getElementById(target);
265→          if (panel) panel.classList.add('active');
266→
267→          trackEvent('tab_switch', { tab: target });
268→        });
269→      });
270→    });
271→  }
272→
273→  // ========== Initialize ==========
274→  document.addEventListener('DOMContentLoaded', function () {
275→    initCookieConsent();
276→    initForms();
277→    initSmoothScroll();
278→    initMobileNav();
279→    initTabs();
280→  });
281→})();
