@media (max-width: 1024px) {
  h1 { font-size: 2.5rem; }
  .hero-title { font-size: 2.8rem; }
}

@media (max-width: 768px) {
  /* Language Switcher */
  .lang-switcher {
    margin-left: 0;
    margin-top: 0.5rem;
    justify-content: center;
    order: 10;
  }

  /* Nav */
  .nav-links {
    display: none;
    position: absolute;
    top: 100%;
    left: 0;
    right: 0;
    background: var(--bg-navy);
    border-bottom: 1px solid var(--border);
    flex-direction: column;
    padding: 1rem 1.5rem;
    gap: 0;
  }

  .nav-links.open {
    display: flex;
  }

  .nav-links li {
    padding: 0.6rem 0;
    border-bottom: 1px solid var(--border);
  }

  .nav-links li:last-child {
    border-bottom: none;
  }

  .nav-toggle {
    display: block;
  }

  /* Hero */
  h1 { font-size: 2rem; }
  .hero { padding: 3rem 0; min-height: auto; }
  .hero-title { font-size: 2.2rem; }
  .hero-subline { font-size: 1rem; }

  /* Product Showcase */
  .product-showcase,
  .showcase-grid {
    grid-template-columns: 1fr;
  }

  .product-showcase .wheel-image,
  .showcase-grid .wheel-image {
    max-width: 300px;
    margin: 0 auto;
  }

  /* Report Meta */
  .report-meta {
    flex-direction: column;
    gap: 0.25rem;
  }

  /* CTA Strip */
  .cta-strip .container {
    flex-direction: column;
    gap: 0.75rem;
    text-align: center;
  }

  .report-section p {
    text-align: left;
  }

