/* ========== Language Switcher (dropdown) ========== */
.lang-switcher {
  position: relative;
  margin-left: 1rem;
}

.lang-btn {
  background: none;
  border: none;
  color: #8b8a94;
  font-size: 0.85rem;
  font-weight: 500;
  cursor: pointer;
  padding: 0.4rem 0.5rem;
  display: flex;
  align-items: center;
  gap: 0.3rem;
  transition: color 0.2s;
  letter-spacing: 0.05em;
}

.lang-btn:hover {
  color: #b0afb8;
}

.lang-arrow {
  transition: transform 0.2s;
}

.lang-btn[aria-expanded="true"] .lang-arrow {
  transform: rotate(180deg);
}

.lang-menu {
